VALUES
  ('cpa-moex-01018', 'cpa', 'cpa-moex-105-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於公司收回自己股份之敘述，下列何者正確？', '["收回特別股之財源，以盈餘或發行新股所得股款為限", "以轉讓予員工為目的而收回之股份，應於一年內轉讓完成", "公司得按市價收回受破產宣告股東之股份，抵償該股東於受破產宣告前結欠公司之債務", "公司因股東依法行使股份收買請求權而收回之股份，應視為未發行股份，並辦理變更登記，不得再予 出售"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "ae55dbd9ed66", "answer_pdf_sha1": "d0fcdb8aa5f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01019', 'cpa', 'cpa-moex-105-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A股份有限公司於民國95年間經董事會決議向證券主管機關申請辦理公開發行股票，並獲得核准。惟於 民國 102 年因經營不善擬引進策略投資人，該策略投資人要求公司必須回復為非公開發行公司之狀態， 則下列所述何者正確？', '["股份有限公司申請公開發行與停止公開發行，均為公司董事會之職權，故由董事會以普通決議為之即 可向證券主管機關申請辦理", "股份有限公司申請公開發行與停止公開發行，均為公司董事會之職權，但應由董事會以特別決議為之 始可向證券主管機關申請辦理", "申請公開發行雖為董事會之職權，但停止公開發行為股東會之職權，須經股東會特別決議始可向證券 主管機關申請辦理", "申請公開發行雖為董事會之職權，但停止公開發行為股東會之職權，僅須經股東會普通決議即可向證 券主管機關申請辦理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "ae55dbd9ed66", "answer_pdf_sha1": "d0fcdb8aa5f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01020', 'cpa', 'cpa-moex-105-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A公司實收資本額為新臺幣10億元，以經營太陽能周邊商品為主要業務，獲利穩定，其資本公積有新臺 幣1億元，累計已提撥法定盈餘公積新臺幣6億元。對於法定盈餘公積之提撥、運用或發給，下列何者 敘述正確？', '["A 公司於完納一切稅捐後，分派盈餘時，應先提出百分之二十為法定盈餘公積。但法定盈餘公積，已 達資本總額時，不在此限", "若A公司本年度虧損新臺幣5,000萬元，應先以資本公積填補資本虧損", "A 公司本年度損益兩平，並無盈餘，但因法定盈餘公積已超過實收資本額百分之五十，仍得經董事會 之決議，以其超過部分派充股息及紅利", "A 公司本年度損益兩平，並無盈餘，得經股東會之特別決議，以法定盈餘公積發給股東新股或現金， 但以該法定盈餘公積超過實收資本額百分之二十五之部分為限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "ae55dbd9ed66", "answer_pdf_sha1": "d0fcdb8aa5f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01021', 'cpa', 'cpa-moex-105-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於股東會議事錄之敘述，下列何者正確？', '["最遲應於股東會後三十日內，將股東會議事錄分發各股東", "議事錄之分發，公開發行股票之公司，得以公告方式為之", "議事錄之保存期限至少為一年。但經股東依公司法第189條提起訴訟者，應保存至訴訟終結為止", "出席股東之簽名簿及代理出席之委託書，在公司存續期間，應永久保存"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "ae55dbd9ed66", "answer_pdf_sha1": "d0fcdb8aa5f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01022', 'cpa', 'cpa-moex-105-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於董事會之說明，下列何者錯誤？', '["董事會開會通知應於開會七日前發出，且經董事同意者得以電子方式發出開會通知，此時即可不發書 面通知", "董事會開會即使章程有特別規定得委託其他董事出席，但因董事會重在討論過程，故章程規定無效， 董事不得委託其他董事代理出席", "董事會以視訊進行者，以視訊參與之董事視為親自出席董事會", "董事會之開會通知必須同時通知監察人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "ae55dbd9ed66", "answer_pdf_sha1": "d0fcdb8aa5f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01023', 'cpa', 'cpa-moex-105-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A 股份有限公司以經營營建工程為主要營業，並未公開發行，則依公司法之規定，下列關於董事義務之 敘述，何者錯誤？', '["董事於董事會執行業務時，應依照法令章程及股東會之決議", "董事對於董事會之會議事項，有自身利害關係時，應於當次董事會說明其自身利害關係之重要內容", "董事發現公司有受重大損害之虞時，應即召集股東會報告", "董事之股份有設定或解除質權者，應即通知公司"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "ae55dbd9ed66", "answer_pdf_sha1": "d0fcdb8aa5f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01024', 'cpa', 'cpa-moex-105-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A股份有限公司有累積虧損新臺幣5億元，卻分派股利給股東，試問債權人B銀行，依公司法規定，得 採取下列何種救濟方式？', '["請求退還，並得請求賠償因此所受之損害", "請求退還，但不得請求賠償因此所受之損害", "請求賠償因此所受之損害，但不得請求退還", "不得請求退還，但得請求懲罰性賠償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "ae55dbd9ed66", "answer_pdf_sha1": "d0fcdb8aa5f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01025', 'cpa', 'cpa-moex-105-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A 公司以經營連鎖餐飲為主要營業，並未公開發行，則依公司法之規定，下列何項議案得於股東會以臨 時動議提出？', '["公司分割之議案", "公司合併之議案", "改選董事與監察人之議案", "對違反競業禁止義務之董事行使歸入權之議案"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "ae55dbd9ed66", "answer_pdf_sha1": "d0fcdb8aa5f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01026', 'cpa', 'cpa-moex-105-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於證券交易法與公司法針對「外國公司」之定義規定，下列何者為其最大的差別？', '["以營利為目的", "依照外國法律組織", "依照外國法律登記", "經中華民國政府認許，在中華民國境內營業"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "ae55dbd9ed66", "answer_pdf_sha1": "d0fcdb8aa5f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01027', 'cpa', 'cpa-moex-105-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '若發行人依證券交易法規定申報或公告之財務報告，其主要內容有虛偽或隱匿之情事致善意投資人發生 損害者，則下列何人非應依其過失責任比例，負賠償責任？', '["發行人之董事長", "發行人之總經理", "財務報告之簽證會計師", "發行人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "ae55dbd9ed66", "answer_pdf_sha1": "d0fcdb8aa5f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01028', 'cpa', 'cpa-moex-105-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '辦理接受客戶委託，在有價證券流通市場代為買賣有價證券之業者，係指下列何者？', '["證券承銷商", "證券自營商", "證券經紀商", "機構投資人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "ae55dbd9ed66", "answer_pdf_sha1": "d0fcdb8aa5f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01029', 'cpa', 'cpa-moex-105-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '公司制證券交易所之董事、監察人，其中由主管機關指派非股東之有關專家任之，其比例至少應有幾分 之幾？', '["二分之一", "三分之一", "三分之二", "五分之二"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "ae55dbd9ed66", "answer_pdf_sha1": "d0fcdb8aa5f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01030', 'cpa', 'cpa-moex-105-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '公開發行公司應於何時向主管機關申報內部控制聲明書？', '["每會計年度終了後三個月內", "每會計年度終了後二個月內", "每會計年度終了後一個月內", "每會計年度終了後立即申報"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "ae55dbd9ed66", "answer_pdf_sha1": "d0fcdb8aa5f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01031', 'cpa', 'cpa-moex-105-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列何者並非屬證券交易法第171條規定，應處三年以上十年以下有期徒刑之罪？', '["違反證券交易法第20條第1項之證券詐欺", "違反證券交易法第155條第1項之證券市場操縱", "已依本法發行有價證券公司之董事、監察人、經理人或受僱人，以直接或間接方式，使公司為不利益 之交易，且不合營業常規，致公司遭受重大損害", "已依本法發行有價證券公司之董事、監察人或經理人，意圖為自己或第三人之利益，而為違背其職務 之行為或侵占公司資產，致公司遭受損害達新臺幣三百萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "ae55dbd9ed66", "answer_pdf_sha1": "d0fcdb8aa5f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
